/**
 * validation.js
 * Reusable input-validation helpers for Express route handlers.
 *
 * Usage:
 *   const { validateUserId, validateUserBody, validationError } = require('./validation');
 *
 *   router.post('/users', (req, res) => {
 *     const errors = validateUserBody(req.body);
 *     if (errors.length) return res.status(400).json(validationError(errors));
 *     // … safe to proceed
 *   });
 */

'use strict';

// RFC-5321 maximum total length for an email address is 254 characters.
const EMAIL_MAX_LENGTH = 254;
const NAME_MIN_LENGTH = 1;
const NAME_MAX_LENGTH = 100;

/**
 * Very permissive but practical email regex.
 * Checks for <local>@<domain>.<tld> shape without being RFC-5322 exhaustive.
 */
const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

// ---------------------------------------------------------------------------
// Primitive validators – each returns an error string or null.
// ---------------------------------------------------------------------------

/**
 * Validates a user ID coming from a URL parameter (always a string).
 * Accepts only positive integers (no floats, no leading zeroes, no negatives).
 *
 * @param {string} raw  - The raw `:id` path parameter string.
 * @returns {string|null}
 */
function validateId(raw) {
  if (raw === undefined || raw === null || raw === '') {
    return 'id is required';
  }
  if (!/^\d+$/.test(String(raw))) {
    return 'id must be a positive integer';
  }
  const num = Number(raw);
  if (!Number.isInteger(num) || num <= 0) {
    return 'id must be a positive integer';
  }
  return null;
}

/**
 * Validates the `name` field from a request body.
 *
 * @param {*} value
 * @returns {string|null}
 */
function validateName(value) {
  if (value === undefined || value === null) {
    return 'name is required';
  }
  if (typeof value !== 'string') {
    return 'name must be a string';
  }
  const trimmed = value.trim();
  if (trimmed.length < NAME_MIN_LENGTH) {
    return `name must be at least ${NAME_MIN_LENGTH} character`;
  }
  if (trimmed.length > NAME_MAX_LENGTH) {
    return `name must be at most ${NAME_MAX_LENGTH} characters`;
  }
  return null;
}

/**
 * Validates the `email` field from a request body.
 *
 * @param {*} value
 * @returns {string|null}
 */
function validateEmail(value) {
  if (value === undefined || value === null) {
    return 'email is required';
  }
  if (typeof value !== 'string') {
    return 'email must be a string';
  }
  if (value.length > EMAIL_MAX_LENGTH) {
    return `email must be at most ${EMAIL_MAX_LENGTH} characters`;
  }
  if (!EMAIL_REGEX.test(value)) {
    return 'email must be a valid email address';
  }
  return null;
}

// ---------------------------------------------------------------------------
// Composite validators – used directly in route handlers.
// ---------------------------------------------------------------------------

/**
 * Validates the `:id` URL parameter.
 *
 * @param {object} params - req.params
 * @returns {string[]} Array of error messages (empty = valid).
 */
function validateUserId(params) {
  const errors = [];
  const idError = validateId(params && params.id);
  if (idError) errors.push(idError);
  return errors;
}

/**
 * Validates the JSON body for creating or fully replacing a user.
 * Both `name` and `email` are required.
 *
 * @param {object} body - req.body
 * @returns {string[]}
 */
function validateUserBody(body) {
  const errors = [];
  if (!body || typeof body !== 'object' || Array.isArray(body)) {
    return ['request body must be a JSON object'];
  }
  const nameError = validateName(body.name);
  if (nameError) errors.push(nameError);

  const emailError = validateEmail(body.email);
  if (emailError) errors.push(emailError);

  return errors;
}

/**
 * Validates the JSON body for a partial user update (PATCH).
 * At least one of `name` or `email` must be supplied; only the
 * fields that ARE present are validated.
 *
 * @param {object} body - req.body
 * @returns {string[]}
 */
function validatePartialUserBody(body) {
  const errors = [];
  if (!body || typeof body !== 'object' || Array.isArray(body)) {
    return ['request body must be a JSON object'];
  }

  const hasName = Object.prototype.hasOwnProperty.call(body, 'name');
  const hasEmail = Object.prototype.hasOwnProperty.call(body, 'email');

  if (!hasName && !hasEmail) {
    return ['at least one field (name, email) must be provided for update'];
  }

  if (hasName) {
    const nameError = validateName(body.name);
    if (nameError) errors.push(nameError);
  }
  if (hasEmail) {
    const emailError = validateEmail(body.email);
    if (emailError) errors.push(emailError);
  }

  return errors;
}

// ---------------------------------------------------------------------------
// Response helper
// ---------------------------------------------------------------------------

/**
 * Builds a standardised 400-error response body.
 *
 * @param {string[]} errors
 * @returns {{ error: string, details: string[] }}
 */
function validationError(errors) {
  return {
    error: 'Validation failed',
    details: errors,
  };
}

// ---------------------------------------------------------------------------
// Exports
// ---------------------------------------------------------------------------

module.exports = {
  validateUserId,
  validateUserBody,
  validatePartialUserBody,
  validationError,
  // Export primitives too so they can be unit-tested individually.
  _validateId: validateId,
  _validateName: validateName,
  _validateEmail: validateEmail,
};

