/**
 * Validation helper module.
 * Each validator returns an array of error strings (empty = valid).
 */

const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

/**
 * Validate a user ID route parameter.
 * @param {string|number} id - value from req.params.id
 * @returns {string[]} array of validation error messages
 */
function validateUserId(id) {
  const errors = [];

  if (id === undefined || id === null || id === '') {
    errors.push('id is required');
    return errors;
  }

  const parsed = Number(id);
  if (!Number.isInteger(parsed) || parsed <= 0) {
    errors.push('id must be a positive integer');
  }

  return errors;
}

/**
 * Validate the body of a create-user request (all fields required).
 * @param {object} body - request body
 * @returns {string[]} array of validation error messages
 */
function validateCreateUser(body) {
  const errors = [];
  const { name, email } = body || {};

  // --- name ---
  if (name === undefined || name === null) {
    errors.push('name is required');
  } else if (typeof name !== 'string') {
    errors.push('name must be a string');
  } else if (name.trim().length < 1) {
    errors.push('name must be at least 1 character');
  } else if (name.length > 100) {
    errors.push('name must not exceed 100 characters');
  }

  // --- email ---
  if (email === undefined || email === null) {
    errors.push('email is required');
  } else if (typeof email !== 'string') {
    errors.push('email must be a string');
  } else if (email.length > 254) {
    errors.push('email must not exceed 254 characters');
  } else if (!EMAIL_REGEX.test(email)) {
    errors.push('email must be a valid email address');
  }

  return errors;
}

/**
 * Validate the body of an update-user request (all fields required).
 * @param {object} body - request body
 * @returns {string[]} array of validation error messages
 */
function validateUpdateUser(body) {
  // Same field rules as create — every field is required on a full update.
  return validateCreateUser(body);
}

/**
 * Validate the body of a partial update-user request (all provided fields
 * are validated, but none is strictly required).
 * @param {object} body - request body
 * @returns {string[]} array of validation error messages
 */
function validatePatchUser(body) {
  const errors = [];
  const { name, email } = body || {};

  if (name !== undefined) {
    if (typeof name !== 'string') {
      errors.push('name must be a string');
    } else if (name.trim().length < 1) {
      errors.push('name must be at least 1 character');
    } else if (name.length > 100) {
      errors.push('name must not exceed 100 characters');
    }
  }

  if (email !== undefined) {
    if (typeof email !== 'string') {
      errors.push('email must be a string');
    } else if (email.length > 254) {
      errors.push('email must not exceed 254 characters');
    } else if (!EMAIL_REGEX.test(email)) {
      errors.push('email must be a valid email address');
    }
  }

  if (name === undefined && email === undefined) {
    errors.push('at least one field (name, email) must be provided');
  }

  return errors;
}

/**
 * Convenience: run a validator and, if there are errors, send a 400 response.
 * Returns true when the request is invalid (caller should return early).
 *
 * @param {Function} validatorFn - one of the validate* functions above
 * @param {*}        input       - value to validate
 * @param {object}   res         - Express response object
 * @returns {boolean} true if invalid (response already sent), false if valid
 */
function rejectIfInvalid(validatorFn, input, res) {
  const errors = validatorFn(input);
  if (errors.length > 0) {
    res.status(400).json({ errors });
    return true;
  }
  return false;
}

module.exports = {
  validateUserId,
  validateCreateUser,
  validateUpdateUser,
  validatePatchUser,
  rejectIfInvalid,
};

