/**
 * Validation helper module.
 *
 * Each validator returns an array of error strings (empty = valid).
 * Use `collectErrors` to run multiple validators and accumulate all failures,
 * then call `sendValidationError` to respond with a structured 400.
 */

'use strict';

// ---------------------------------------------------------------------------
// Primitive validators
// ---------------------------------------------------------------------------

/**
 * Validates that every key in `requiredFields` is present and non-empty on
 * `body`.  "Present" means the key exists AND the value is not undefined,
 * null, or an empty string.
 *
 * @param {object} body
 * @param {string[]} requiredFields
 * @returns {string[]} error messages
 */
function validateRequired(body, requiredFields) {
  const errors = [];
  for (const field of requiredFields) {
    const value = body[field];
    if (value === undefined || value === null || value === '') {
      errors.push(`'${field}' is required`);
    }
  }
  return errors;
}

/**
 * Validates that `value` is a finite integer (or a string that parses to one).
 * Returns an error string on failure, or null on success.
 *
 * @param {*} value
 * @param {string} fieldName  – used in the error message
 * @returns {string|null}
 */
function validateNumericId(value, fieldName = 'id') {
  const num = Number(value);
  if (!Number.isFinite(num) || !Number.isInteger(num)) {
    return `'${fieldName}' must be a numeric integer (received: ${JSON.stringify(value)})`;
  }
  return null;
}

/**
 * Validates that `value` is a non-null string.
 *
 * @param {*} value
 * @param {string} fieldName
 * @returns {string|null}
 */
function validateString(value, fieldName) {
  if (typeof value !== 'string') {
    return `'${fieldName}' must be a string (received: ${typeof value})`;
  }
  return null;
}

/**
 * Validates that a string value's length falls within [min, max] (inclusive).
 * Assumes `value` has already passed `validateString`.
 *
 * @param {string} value
 * @param {string} fieldName
 * @param {number} min
 * @param {number} max
 * @returns {string|null}
 */
function validateStringLength(value, fieldName, min, max) {
  if (typeof value !== 'string') return null; // let validateString handle type errors
  if (value.length < min || value.length > max) {
    return `'${fieldName}' must be between ${min} and ${max} characters (received: ${value.length})`;
  }
  return null;
}

/**
 * Validates that `value` matches a broadly RFC-5321-compliant email pattern.
 * Max length is enforced separately via validateStringLength.
 *
 * @param {*} value
 * @param {string} fieldName
 * @returns {string|null}
 */
function validateEmail(value, fieldName = 'email') {
  if (typeof value !== 'string') return null; // type error handled elsewhere
  // local-part @ domain.tld  (no consecutive dots, no leading/trailing dots)
  const EMAIL_RE = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  if (!EMAIL_RE.test(value)) {
    return `'${fieldName}' must be a valid email address (received: ${JSON.stringify(value)})`;
  }
  return null;
}

// ---------------------------------------------------------------------------
// Composite field validators (combine type + length + format checks)
// ---------------------------------------------------------------------------

/**
 * Runs all applicable validations for a `name` field if it is present in
 * `body`.  Pass `required: true` to also flag a missing / empty value.
 *
 * @param {object} body
 * @param {{ required?: boolean }} [opts]
 * @returns {string[]}
 */
function validateNameField(body, { required = false } = {}) {
  const errors = [];
  const { name } = body;

  if (name === undefined || name === null || name === '') {
    if (required) errors.push("'name' is required");
    return errors; // nothing more to check
  }

  const typeError = validateString(name, 'name');
  if (typeError) { errors.push(typeError); return errors; }

  const lengthError = validateStringLength(name, 'name', 1, 100);
  if (lengthError) errors.push(lengthError);

  return errors;
}

/**
 * Runs all applicable validations for an `email` field if it is present in
 * `body`.  Pass `required: true` to also flag a missing / empty value.
 *
 * @param {object} body
 * @param {{ required?: boolean }} [opts]
 * @returns {string[]}
 */
function validateEmailField(body, { required = false } = {}) {
  const errors = [];
  const { email } = body;

  if (email === undefined || email === null || email === '') {
    if (required) errors.push("'email' is required");
    return errors;
  }

  const typeError = validateString(email, 'email');
  if (typeError) { errors.push(typeError); return errors; }

  const lengthError = validateStringLength(email, 'email', 1, 254);
  if (lengthError) errors.push(lengthError);

  const formatError = validateEmail(email, 'email');
  if (formatError) errors.push(formatError);

  return errors;
}

/**
 * Validates a route parameter that must be a numeric integer ID.
 *
 * @param {object} params  – req.params
 * @param {string} paramName
 * @returns {string[]}
 */
function validateIdParam(params, paramName = 'id') {
  const errors = [];
  const value = params[paramName];

  if (value === undefined || value === null || value === '') {
    errors.push(`'${paramName}' parameter is required`);
    return errors;
  }

  const idError = validateNumericId(value, paramName);
  if (idError) errors.push(idError);

  return errors;
}

// ---------------------------------------------------------------------------
// Response helper
// ---------------------------------------------------------------------------

/**
 * Sends a structured 400 JSON response listing all validation errors.
 *
 * @param {import('express').Response} res
 * @param {string[]} errors
 */
function sendValidationError(res, errors) {
  return res.status(400).json({
    error: 'Validation failed',
    details: errors,
  });
}

// ---------------------------------------------------------------------------
// Exports
// ---------------------------------------------------------------------------

module.exports = {
  validateRequired,
  validateNumericId,
  validateString,
  validateStringLength,
  validateEmail,
  validateNameField,
  validateEmailField,
  validateIdParam,
  sendValidationError,
