/**
 * Validation helper module.
 * Each exported function returns an array of error message strings.
 * An empty array means all validations passed.
 */

// RFC 5321 / RFC 5322 compliant-enough email regex (covers the vast majority of real addresses)
const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

/**
 * Validate a user `id` from a route parameter.
 *  - Must be present
 *  - Must be a whole, positive number
 *
 * @param {string} raw - The raw string value from req.params.id
 * @returns {string[]} Array of validation error messages
 */
function validateUserId(raw) {
  const errors = [];

  if (raw === undefined || raw === null || raw === '') {
    errors.push('id is required');
    return errors; // no further checks make sense
  }

  const num = Number(raw);
  if (!Number.isInteger(num) || num <= 0) {
    errors.push('id must be a positive integer');
  }

  return errors;
}

/**
 * Validate a `name` field from a request body.
 *  - Must be present and non-empty after trimming
 *  - Must be a string
 *  - Must be 1–100 characters (post-trim)
 *
 * @param {*} value - The raw value from req.body.name
 * @returns {string[]} Array of validation error messages
 */
function validateName(value) {
  const errors = [];

  if (value === undefined || value === null) {
    errors.push('name is required');
    return errors;
  }

  if (typeof value !== 'string') {
    errors.push('name must be a string');
    return errors;
  }

  const trimmed = value.trim();

  if (trimmed.length === 0) {
    errors.push('name must not be empty');
  } else if (trimmed.length > 100) {
    errors.push(`name must be at most 100 characters (received ${trimmed.length})`);
  }

  return errors;
}

/**
 * Validate an `email` field from a request body.
 *  - Must be present and non-empty after trimming
 *  - Must be a string
 *  - Must match a basic email format
 *  - Must be at most 254 characters (the RFC 5321 maximum)
 *
 * @param {*} value - The raw value from req.body.email
 * @returns {string[]} Array of validation error messages
 */
function validateEmail(value) {
  const errors = [];

  if (value === undefined || value === null) {
    errors.push('email is required');
    return errors;
  }

  if (typeof value !== 'string') {
    errors.push('email must be a string');
    return errors;
  }

  const trimmed = value.trim();

  if (trimmed.length === 0) {
    errors.push('email must not be empty');
    return errors;
  }

  if (trimmed.length > 254) {
    errors.push(`email must be at most 254 characters (received ${trimmed.length})`);
  }

  if (!EMAIL_REGEX.test(trimmed)) {
    errors.push('email must be a valid email address (e.g. user@example.com)');
  }

  return errors;
}

/**
 * Validate all fields required to create a new user (POST body).
 *  - name  (required)
 *  - email (required)
 *
 * @param {object} body - req.body
 * @returns {string[]} Aggregated array of validation error messages
 */
function validateCreateUser(body) {
  return [
    ...validateName(body.name),
    ...validateEmail(body.email),
  ];
}

/**
 * Validate all fields required to fully update an existing user (PUT body).
 *  - name  (required)
 *  - email (required)
 *
 * @param {object} body - req.body
 * @returns {string[]} Aggregated array of validation error messages
 */
function validateUpdateUser(body) {
  return [
    ...validateName(body.name),
    ...validateEmail(body.email),
  ];
}

module.exports = {
  validateUserId,
  validateName,
  validateEmail,
  validateCreateUser,
  validateUpdateUser,
};
